import { useState, useEffect, useCallback } from "react";
import axios from "axios";
import "./styles/global.css";

// Importação dos componentes
import Navbar      from "./components/Navbar";
import Hero        from "./components/Hero";
import FormPanel   from "./components/FormPanel";
import TablePanel  from "./components/TablePanel";
import DeleteModal from "./components/DeleteModal";
import Toast       from "./components/Toast";
import Footer      from "./components/Footer";
import LandingPage from "./components/LandingPage"; // Importando a nova página

import { EMPTY_FORM } from "./constants";

const API_URL = "http://localhost:8080/agendamento";

export default function App() {
  // Estado para controlar qual página exibir: 'landing' ou 'schedule'
  const [view, setView] = useState("landing");

  const [appointments, setAppointments] = useState([]);
  const [form, setForm] = useState(EMPTY_FORM);
  const [editingId, setEditingId] = useState(null);
  const [activeNav, setActiveNav] = useState("Início");
  const [deleteTarget, setDeleteTarget] = useState(null);
  const [toast, setToast] = useState(null);

  const showToast = (msg, type = "success") => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  };

  const fetchAppointments = useCallback(async () => {
    try {
      const response = await axios.get(API_URL);
      const formattedData = response.data.map(item => ({
        id: item.id,
        name: item.clienteNome,
        service: item.servico,
        date: item.dataHora.split('T')[0],
        time: item.dataHora.split('T')[1].substring(0, 5),
        status: "confirmado"
      }));
      setAppointments(formattedData);
    } catch (error) {
      console.error("Erro API:", error);
    }
  }, []);

  useEffect(() => {
    if (view === "schedule") fetchAppointments();
  }, [view, fetchAppointments]);

  const handleSubmit = async () => {
    if (!form.name || !form.service || !form.date || !form.time) {
      showToast("Preencha todos os campos.", "error");
      return;
    }
    const payload = {
      clienteNome: form.name,
      servico: form.service,
      dataHora: `${form.date}T${form.time}:00`
    };
    try {
      if (editingId !== null) {
        await axios.put(`${API_URL}/${editingId}`, payload);
        showToast("Atualizado com sucesso!");
        setEditingId(null);
      } else {
        await axios.post(API_URL, payload);
        showToast("Criado com sucesso!");
      }
      setForm(EMPTY_FORM);
      fetchAppointments();
    } catch (error) {
      showToast("Erro ao salvar.", "error");
    }
  };

  const handleEdit = (appt) => {
    setForm({ name: appt.name, service: appt.service, date: appt.date, time: appt.time });
    setEditingId(appt.id);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // RENDERIZAÇÃO CONDICIONAL
  if (view === "landing") {
    return <LandingPage onNavigate={() => setView("schedule")} />;
  }

  return (
    <div className="animate-reveal">
      {/* Botão flutuante para voltar para a Home */}
      <button 
        onClick={() => setView("landing")}
        className="fixed bottom-10 right-10 z-[100] bg-pbBlack text-pbYellow p-4 rounded-full shadow-2xl hover:scale-110 transition-all font-bold border-2 border-pbYellow"
      >
        ← Voltar para Home
      </button>

      <Navbar active={activeNav} setActive={setActiveNav} />
      <Hero />
      <div className="pb-main-grid">
        <FormPanel
          form={form}
          setForm={setForm}
          editing={editingId !== null}
          onSubmit={handleSubmit}
          onCancel={() => {setForm(EMPTY_FORM); setEditingId(null);}}
        />
        <TablePanel
          appointments={appointments}
          onEdit={handleEdit}
          onDeleteRequest={setDeleteTarget}
        />
      </div>
      <Footer />
      <DeleteModal
        target={deleteTarget}
        onConfirm={async (id) => {
            await axios.delete(`${API_URL}/${id}`);
            setDeleteTarget(null);
            fetchAppointments();
        }}
        onCancel={() => setDeleteTarget(null)}
      />
      <Toast toast={toast} />
    </div>
  );
}
